import React, { useState } from 'react';
import { useStudioStore } from '../../store/useStudioStore';
import { format } from 'date-fns';
import { AgentomaticClient } from '../../api/client';
import { useEffect } from 'react';
import toast from 'react-hot-toast';
import { ClipboardDocumentIcon, ChevronLeftIcon, ChevronRightIcon } from '@heroicons/react/24/outline';

export const DebugView: React.FC = () => {
  const { graphState, selectedThread, darkMode, executionContext, selectedAgent, config } = useStudioStore();
  const [activeTab, setActiveTab] = useState<'state' | 'history' | 'steps' | 'logs' | 'performance'>('state');
  const [searchTerm, setSearchTerm] = useState('');
  const [logLevel, setLogLevel] = useState<'ALL' | 'ERROR' | 'WARN' | 'INFO' | 'DEBUG'>('ALL');
  const [checkpointIndex, setCheckpointIndex] = useState(0);

  const [realState, setRealState] = useState<any>(null);
  const [realHistory, setRealHistory] = useState<any[]>([]);
  const [isLoadingState, setIsLoadingState] = useState(false);
  const [stateError, setStateError] = useState<string | undefined>(undefined);

  // Load real state from API when available
  useEffect(() => {
    const loadState = async () => {
      if (!selectedAgent?.id || !selectedThread?.id || !config?.apiUrl) return;
      setIsLoadingState(true);
      try {
        const client = new AgentomaticClient(config.apiUrl, config.apiKey);
        const snapshot = await client.getState(selectedAgent.id, selectedThread.id);
        setRealState(snapshot);
        setStateError(undefined);
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        console.log('Could not load real state, using execution context', message);
        setStateError(message);
      }
      try {
        const client = new AgentomaticClient(config.apiUrl, config.apiKey);
        const history = await client.getHistory(selectedAgent.id, selectedThread.id);
        setRealHistory(history);
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        console.log('Could not load history', message);
        setStateError((prev) => prev || message);
      }
      setIsLoadingState(false);
    };
    loadState();
  }, [selectedAgent?.id, selectedThread?.id, config?.apiUrl, config?.apiKey]);

  // Merge real-time state updates from executionContext during execution
  const liveVariables = executionContext.isExecuting && executionContext.currentState && Object.keys(executionContext.currentState).length > 0
    ? { ...(realState?.state || {}), ...executionContext.currentState }
    : undefined;

  const debugState = realState ? {
    messages: selectedThread?.messages || [],
    current_node: graphState?.currentNode || realState.state?.current_node || 'agent',
    execution_path: graphState?.executionPath || [],
    variables: liveVariables || realState.state || executionContext.currentState || {},
    metadata: {
      agent_name: realState.agent_name || selectedAgent?.name || 'unknown',
      thread_id: realState.thread_id || selectedThread?.id || 'unknown',
      checkpoint_id: realState.checkpoint_id || null,
      timestamp: realState.timestamp || new Date().toISOString(),
    }
  } : {
    messages: selectedThread?.messages || [],
    current_node: graphState?.currentNode || 'agent',
    execution_path: graphState?.executionPath || [],
    variables: liveVariables || executionContext.currentState || {},
    metadata: {
      agent_name: selectedAgent?.name || 'unknown',
      thread_id: selectedThread?.id || 'unknown',
      timestamp: new Date().toISOString(),
    }
  };

  const debugSteps = executionContext.logs
    .filter(log => log.type === 'input' || log.type === 'output')
    .reduce((acc: any[], log, idx) => {
      const existing = acc.find(s => s.node === log.nodeId);
      if (existing) {
        if (log.type === 'output') {
          existing.status = 'completed';
          existing.output = log.data?.output || log.data;
          existing.duration = log.duration || null;
        }
      } else {
        acc.push({
          id: log.id || `step_${idx}`,
          node: log.nodeId,
          status: log.type === 'output' ? 'completed' : (log.type === 'error' ? 'error' : 'running'),
          input: log.type === 'input' ? (log.data?.input || log.data) : null,
          output: log.type === 'output' ? (log.data?.output || log.data) : null,
          timestamp: log.timestamp,
          duration: log.duration || null,
          tokens_used: 0,
        });
      }
      return acc;
    }, []);

  const debugLogs = executionContext.logs.map(log => ({
    level: log.type === 'error' ? 'ERROR' : log.type === 'debug' ? 'DEBUG' : log.type === 'info' ? 'INFO' : 'INFO',
    message: log.message,
    timestamp: log.timestamp,
    node: log.nodeId,
    details: log.data || {}
  }));

  const debugPerformance = {
    total_execution_time: executionContext.startTime && executionContext.endTime 
      ? executionContext.endTime.getTime() - executionContext.startTime.getTime() 
      : executionContext.startTime ? Date.now() - executionContext.startTime.getTime() : 0,
    node_performance: Object.entries(
      executionContext.logs.reduce((acc: Record<string, {total: number, count: number}>, log) => {
        if (log.duration !== undefined) {
          if (!acc[log.nodeId]) acc[log.nodeId] = { total: 0, count: 0 };
          acc[log.nodeId].total += log.duration;
          acc[log.nodeId].count += 1;
        }
        return acc;
      }, {})
    ).map(([node, data]: [string, any]) => ({
      node,
      avg_duration: Number((data.total / data.count).toFixed(2)),
      calls: data.count,
      total_time: Number((data.total).toFixed(2)),
    })),
    memory_usage: { current: 'N/A', peak: 'N/A', average: 'N/A' },
    token_usage: executionContext.logs.reduce((acc, log: any) => {
      const tokens = log.data?.output?.metadata?.tokens_used || log.data?.metadata?.tokens_used || 0;
      if (tokens) {
        acc.total += tokens;
      }
      return acc;
    }, { total: 0, input: 0, output: 0, cost_estimate: '$0.00' })
  };

  const filteredLogs = debugLogs.filter(log => {
    const matchesSearch = log.message.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         log.node.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesLevel = logLevel === 'ALL' || log.level === logLevel;
    return matchesSearch && matchesLevel;
  });

  return (
    <div className={`h-full flex flex-col transition-all duration-300 ${
      darkMode ? 'bg-gray-900' : 'bg-gray-50'
    }`}>
      {stateError && (
        <div
          className={`px-4 py-3 text-sm border-b ${
            darkMode
              ? 'bg-red-900/40 border-red-700 text-red-200'
              : 'bg-red-50 border-red-200 text-red-800'
          }`}
          role="alert"
        >
          <strong>Debug load error:</strong> {stateError}
        </div>
      )}
      {/* Modern Header with Gradient */}
      <div className={`relative overflow-hidden ${
        darkMode 
          ? 'bg-gradient-to-r from-gray-800 via-gray-700 to-gray-800' 
          : 'bg-gradient-to-r from-blue-50 via-white to-purple-50'
      }`}>
        <div className="absolute inset-0 bg-grid-pattern opacity-5"></div>
        <div className="relative p-6 border-b border-gray-200 dark:border-gray-700">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <div className={`p-3 rounded-xl ${
                darkMode ? 'bg-blue-600/20 text-blue-400' : 'bg-blue-100 text-blue-600'
              }`}>
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div>
                <h2 className={`text-2xl font-bold ${darkMode ? 'text-white' : 'text-gray-900'}`}>
                  Debug Console
                </h2>
                <p className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>
                  Real-time graph execution monitoring and analysis
                </p>
              </div>
            </div>
            
            {/* Status Indicators */}
            <div className="flex items-center space-x-3">
              <div className={`flex items-center space-x-2 px-3 py-2 rounded-lg ${
                darkMode ? 'bg-gray-700/50' : 'bg-white/50'
              } backdrop-blur-sm`}>
                <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                <span className={`text-sm font-medium ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                  Live
                </span>
              </div>
              <div className={`px-3 py-2 rounded-lg ${
                darkMode ? 'bg-gray-700/50' : 'bg-white/50'
              } backdrop-blur-sm`}>
                <span className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>
                  {debugSteps.filter(s => s.status === 'completed').length}/{debugSteps.length} Steps
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Enhanced Tab Navigation */}
      <div className={`border-b ${darkMode ? 'border-gray-700 bg-gray-800' : 'border-gray-200 bg-white'}`}>
        <div className="px-6">
          <nav className="flex space-x-8">
            {[
              { id: 'state', label: 'State', icon: '🔍', count: Object.keys(debugState.variables).length },
              { id: 'history', label: 'Time Travel', icon: '⏪', count: realHistory.length },
              { id: 'steps', label: 'Steps', icon: '📋', count: debugSteps.length },
              { id: 'logs', label: 'Logs', icon: '📝', count: filteredLogs.length },
              { id: 'performance', label: 'Performance', icon: '⚡', count: debugPerformance.node_performance.length },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`relative py-4 px-1 font-medium text-sm transition-all duration-200 ${
                  activeTab === tab.id
                    ? darkMode 
                      ? 'text-blue-400 border-b-2 border-blue-400' 
                      : 'text-blue-600 border-b-2 border-blue-500'
                    : darkMode 
                      ? 'text-gray-400 hover:text-gray-200' 
                      : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <div className="flex items-center space-x-2">
                  <span>{tab.icon}</span>
                  <span>{tab.label}</span>
                  <span className={`px-2 py-1 text-xs rounded-full ${
                    activeTab === tab.id
                      ? darkMode ? 'bg-blue-600 text-white' : 'bg-blue-100 text-blue-600'
                      : darkMode ? 'bg-gray-700 text-gray-400' : 'bg-gray-100 text-gray-600'
                  }`}>
                    {tab.count}
                  </span>
                </div>
              </button>
            ))}
          </nav>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-hidden">
        {activeTab === 'state' && <StateView state={debugState} darkMode={darkMode} isExecuting={executionContext.isExecuting} />}
        {activeTab === 'history' && (
          <HistoryView
            history={realHistory}
            darkMode={darkMode}
            checkpointIndex={checkpointIndex}
            setCheckpointIndex={setCheckpointIndex}
          />
        )}
        {activeTab === 'steps' && <StepsView steps={debugSteps} darkMode={darkMode} />}
        {activeTab === 'logs' && (
          <LogsView 
            logs={filteredLogs} 
            darkMode={darkMode}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
            logLevel={logLevel}
            setLogLevel={setLogLevel}
          />
        )}
        {activeTab === 'performance' && <PerformanceView performance={debugPerformance} darkMode={darkMode} />}
      </div>
    </div>
  );
};

const StateView: React.FC<{ state: any; darkMode: boolean; isExecuting: boolean }> = ({ state, darkMode, isExecuting }) => {
  const [expandedSections, setExpandedSections] = useState<Set<string>>(new Set(['variables']));
  const [isEditing, setIsEditing] = useState(false);
  const [editValue, setEditValue] = useState('');
  const { selectedAgent, selectedThread, config } = useStudioStore();

  const handleCopyJson = async () => {
    try {
      await navigator.clipboard.writeText(JSON.stringify(state.variables, null, 2));
      toast.success('State JSON copied to clipboard');
    } catch {
      toast.error('Failed to copy to clipboard');
    }
  };

  const handleEditClick = () => {
    setEditValue(JSON.stringify(state.variables, null, 2));
    setIsEditing(true);
  };

  const handleSaveState = async () => {
    try {
      const parsed = JSON.parse(editValue);
      if (selectedAgent && selectedThread && config?.apiUrl) {
        const client = new AgentomaticClient(config.apiUrl, config.apiKey);
        await client.updateState(selectedAgent.id, selectedThread.id, parsed);
        alert('State updated successfully!');
        setIsEditing(false);
      }
    } catch (e) {
      alert('Invalid JSON format');
    }
  };

  const toggleSection = (section: string) => {
    const newExpanded = new Set(expandedSections);
    if (newExpanded.has(section)) {
      newExpanded.delete(section);
    } else {
      newExpanded.add(section);
    }
    setExpandedSections(newExpanded);
  };

  return (
    <div className="h-full overflow-y-auto p-6 custom-scrollbar">
      <div className="max-w-6xl mx-auto space-y-6">
        {/* Execution Overview */}
        <div className={`rounded-xl border p-6 ${
          darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'
        }`}>
          <h3 className={`text-lg font-semibold mb-4 flex items-center ${darkMode ? 'text-white' : 'text-gray-900'}`}>
            <svg className="w-5 h-5 mr-2 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            Execution Overview
            {isExecuting && (
              <span className="ml-3 flex items-center space-x-2">
                <span className="relative flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
                </span>
                <span className={`text-xs font-normal ${darkMode ? 'text-green-400' : 'text-green-600'}`}>Live updating</span>
              </span>
            )}
          </h3>
          
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className={`p-4 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
              <div className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Current Node</div>
              <div className={`text-xl font-bold ${darkMode ? 'text-blue-400' : 'text-blue-600'}`}>
                {state.current_node}
              </div>
            </div>
            <div className={`p-4 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
              <div className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Steps Completed</div>
              <div className={`text-xl font-bold ${darkMode ? 'text-green-400' : 'text-green-600'}`}>
                {state.execution_path?.length || 0}
              </div>
            </div>
            <div className={`p-4 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
              <div className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Total Messages</div>
              <div className={`text-xl font-bold ${darkMode ? 'text-purple-400' : 'text-purple-600'}`}>
                {state.messages?.length || 0}
              </div>
            </div>
          </div>
        </div>

        {/* Execution Path */}
        <div className={`rounded-xl border p-6 ${
          darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'
        }`}>
          <h3 className={`text-lg font-semibold mb-4 ${darkMode ? 'text-white' : 'text-gray-900'}`}>
            Execution Path
          </h3>
          <div className="flex items-center space-x-2 flex-wrap gap-2">
            {state.execution_path?.map((node: string, index: number) => (
              <React.Fragment key={`${node}-${index}`}>
                <div className={`flex items-center px-4 py-2 rounded-lg border-2 ${
                  darkMode ? 'bg-blue-600 border-blue-500 text-white' : 'bg-blue-50 border-blue-200 text-blue-700'
                }`}>
                  <span className={`w-6 h-6 rounded-full flex items-center justify-center mr-2 text-xs font-bold ${
                    darkMode ? 'bg-blue-500' : 'bg-blue-200'
                  }`}>
                    {index + 1}
                  </span>
                  {node}
                </div>
                {index < state.execution_path.length - 1 && (
                  <svg className={`w-5 h-5 ${darkMode ? 'text-gray-500' : 'text-gray-400'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                  </svg>
                )}
              </React.Fragment>
            ))}
          </div>
        </div>

        {/* Variables Section */}
        <div className={`rounded-xl border ${
          darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'
        }`}>
          <div className={`px-6 pb-6 pt-6 flex items-center justify-between`}>
            <div className="flex items-center space-x-4">
              <h3 className={`text-lg font-semibold ${darkMode ? 'text-white' : 'text-gray-900'}`}>
                State Variables ({Object.keys(state.variables || {}).length})
              </h3>
              <button
                onClick={handleCopyJson}
                className={`flex items-center space-x-1 px-3 py-1 text-xs rounded border transition-colors ${
                  darkMode
                    ? 'bg-gray-700 border-gray-600 text-gray-200 hover:bg-gray-600'
                    : 'bg-white border-gray-300 text-gray-700 hover:bg-gray-50'
                }`}
                title="Copy state JSON to clipboard"
              >
                <ClipboardDocumentIcon className="w-3.5 h-3.5" />
                <span>Copy JSON</span>
              </button>
              {!isEditing ? (
                <button onClick={handleEditClick} className={`px-3 py-1 text-xs rounded border ${darkMode ? 'bg-gray-700 border-gray-600 text-gray-200' : 'bg-white border-gray-300 text-gray-700'}`}>
                  Edit State
                </button>
              ) : (
                <div className="flex space-x-2">
                  <button onClick={handleSaveState} className={`px-3 py-1 text-xs rounded border bg-blue-600 text-white border-blue-700`}>
                    Save
                  </button>
                  <button onClick={() => setIsEditing(false)} className={`px-3 py-1 text-xs rounded border ${darkMode ? 'bg-gray-700 border-gray-600 text-gray-200' : 'bg-white border-gray-300 text-gray-700'}`}>
                    Cancel
                  </button>
                </div>
              )}
            </div>
            <button onClick={() => toggleSection('variables')}>
              <svg 
                className={`w-5 h-5 transition-transform ${expandedSections.has('variables') ? 'rotate-90' : ''} ${darkMode ? 'text-gray-400' : 'text-gray-500'}`} 
                fill="none" 
                stroke="currentColor" 
                viewBox="0 0 24 24"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
              </svg>
            </button>
          </div>
          
          {expandedSections.has('variables') && (
            <div className={`mx-6 mb-6 p-4 rounded-lg overflow-x-auto ${darkMode ? 'bg-gray-900' : 'bg-gray-50'}`}>
              {isEditing ? (
                <textarea 
                  className={`w-full h-64 p-2 font-mono text-sm rounded ${darkMode ? 'bg-gray-800 text-green-400' : 'bg-white text-green-600'}`}
                  value={editValue}
                  onChange={e => setEditValue(e.target.value)}
                />
              ) : (
                <pre className={`text-sm font-mono ${darkMode ? 'text-green-400' : 'text-green-600'}`}>
                  {JSON.stringify(state.variables, null, 2)}
                </pre>
              )}
            </div>
          )}
        </div>

        {/* Metadata Section */}
        <div className={`rounded-xl border ${
          darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'
        }`}>
          <button
            onClick={() => toggleSection('metadata')}
            className={`w-full p-6 text-left flex items-center justify-between ${
              darkMode ? 'hover:bg-gray-700' : 'hover:bg-gray-50'
            } transition-colors rounded-t-xl`}
          >
            <h3 className={`text-lg font-semibold ${darkMode ? 'text-white' : 'text-gray-900'}`}>
              Metadata
            </h3>
            <svg 
              className={`w-5 h-5 transition-transform ${
                expandedSections.has('metadata') ? 'rotate-90' : ''
              } ${darkMode ? 'text-gray-400' : 'text-gray-500'}`} 
              fill="none" 
              stroke="currentColor" 
              viewBox="0 0 24 24"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          </button>
          
          {expandedSections.has('metadata') && (
            <div className="px-6 pb-6">
              <div className={`rounded-lg p-4 ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                <pre className={`text-sm font-mono whitespace-pre-wrap ${
                  darkMode ? 'text-gray-300' : 'text-gray-700'
                }`}>
                  {JSON.stringify(state.metadata, null, 2)}
                </pre>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const StepsView: React.FC<{ steps: any[]; darkMode: boolean }> = ({ steps, darkMode }) => {
  const [expandedSteps, setExpandedSteps] = useState<Set<string>>(new Set());

  const toggleStep = (stepId: string) => {
    const newExpanded = new Set(expandedSteps);
    if (newExpanded.has(stepId)) {
      newExpanded.delete(stepId);
    } else {
      newExpanded.add(stepId);
    }
    setExpandedSteps(newExpanded);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'text-green-600 bg-green-100 border-green-200';
      case 'running': return 'text-blue-600 bg-blue-100 border-blue-200';
      case 'error': return 'text-red-600 bg-red-100 border-red-200';
      default: return 'text-gray-600 bg-gray-100 border-gray-200';
    }
  };

  const getDarkStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'text-green-400 bg-green-900/30 border-green-700';
      case 'running': return 'text-blue-400 bg-blue-900/30 border-blue-700';
      case 'error': return 'text-red-400 bg-red-900/30 border-red-700';
      default: return 'text-gray-400 bg-gray-800 border-gray-600';
    }
  };

  return (
    <div className="h-full overflow-y-auto p-6 custom-scrollbar">
      <div className="max-w-4xl mx-auto space-y-4">
        {steps.map((step, index) => {
          const isExpanded = expandedSteps.has(step.id);
          const statusColors = darkMode ? getDarkStatusColor(step.status) : getStatusColor(step.status);
          
          return (
            <div key={step.id} className={`rounded-xl border transition-all duration-200 ${
              darkMode ? 'border-gray-700 bg-gray-800' : 'border-gray-200 bg-white'
            } hover:shadow-lg`}>
              <button
                onClick={() => toggleStep(step.id)}
                className={`w-full p-6 text-left ${
                  darkMode ? 'hover:bg-gray-700' : 'hover:bg-gray-50'
                } transition-colors rounded-t-xl`}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-4">
                    <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold ${
                      darkMode ? 'bg-blue-600 text-white' : 'bg-blue-100 text-blue-600'
                    }`}>
                      {index + 1}
                    </div>
                    <div>
                      <h4 className={`text-lg font-semibold ${darkMode ? 'text-white' : 'text-gray-900'}`}>
                        {step.node}
                      </h4>
                      <p className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                        Step ID: {step.id}
                      </p>
                    </div>
                  </div>
                  
                  <div className="flex items-center space-x-3">
                    <div className={`px-3 py-1 rounded-full text-sm font-medium border ${statusColors}`}>
                      {step.status}
                    </div>
                    {step.duration && (
                      <div className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                        {step.duration}ms
                      </div>
                    )}
                    <svg 
                      className={`w-5 h-5 transition-transform ${
                        isExpanded ? 'rotate-90' : ''
                      } ${darkMode ? 'text-gray-400' : 'text-gray-500'}`} 
                      fill="none" 
                      stroke="currentColor" 
                      viewBox="0 0 24 24"
                    >
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                    </svg>
                  </div>
                </div>
              </button>

              {isExpanded && (
                <div className={`px-6 pb-6 border-t ${darkMode ? 'border-gray-700' : 'border-gray-200'}`}>
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-6">
                    {step.input && (
                      <div>
                        <h5 className={`text-sm font-semibold mb-3 ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                          Input Data
                        </h5>
                        <div className={`rounded-lg p-4 ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                          <pre className={`text-sm font-mono whitespace-pre-wrap ${
                            darkMode ? 'text-gray-300' : 'text-gray-700'
                          }`}>
                            {JSON.stringify(step.input, null, 2)}
                          </pre>
                        </div>
                      </div>
                    )}

                    {step.output && (
                      <div>
                        <h5 className={`text-sm font-semibold mb-3 ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                          Output Data
                        </h5>
                        <div className={`rounded-lg p-4 ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                          <pre className={`text-sm font-mono whitespace-pre-wrap ${
                            darkMode ? 'text-gray-300' : 'text-gray-700'
                          }`}>
                            {JSON.stringify(step.output, null, 2)}
                          </pre>
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Step Metrics */}
                  <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className={`p-3 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                      <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Timestamp</div>
                      <div className={`text-sm font-medium ${darkMode ? 'text-gray-200' : 'text-gray-900'}`}>
                        {step.timestamp ? format(step.timestamp, 'HH:mm:ss.SSS') : 'Pending'}
                      </div>
                    </div>
                    <div className={`p-3 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                      <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Duration</div>
                      <div className={`text-sm font-medium ${darkMode ? 'text-gray-200' : 'text-gray-900'}`}>
                        {step.duration ? `${step.duration}ms` : 'N/A'}
                      </div>
                    </div>
                    <div className={`p-3 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                      <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Tokens Used</div>
                      <div className={`text-sm font-medium ${darkMode ? 'text-gray-200' : 'text-gray-900'}`}>
                        {step.tokens_used || 0}
                      </div>
                    </div>
                    <div className={`p-3 rounded-lg ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                      <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>Status</div>
                      <div className={`text-sm font-medium ${darkMode ? 'text-gray-200' : 'text-gray-900'}`}>
                        {step.status}
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

const LogsView: React.FC<{ 
  logs: any[]; 
  darkMode: boolean;
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  logLevel: string;
  setLogLevel: (level: any) => void;
}> = ({ logs, darkMode, searchTerm, setSearchTerm, logLevel, setLogLevel }) => {
  const getLevelColor = (level: string) => {
    switch (level) {
      case 'ERROR': return darkMode ? 'text-red-400 bg-red-900/30' : 'text-red-700 bg-red-50';
      case 'WARN': return darkMode ? 'text-yellow-400 bg-yellow-900/30' : 'text-yellow-700 bg-yellow-50';
      case 'INFO': return darkMode ? 'text-blue-400 bg-blue-900/30' : 'text-blue-700 bg-blue-50';
      case 'DEBUG': return darkMode ? 'text-gray-400 bg-gray-800' : 'text-gray-700 bg-gray-100';
      default: return darkMode ? 'text-gray-400 bg-gray-800' : 'text-gray-700 bg-gray-100';
    }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Search and Filter Bar */}
      <div className={`p-4 border-b ${darkMode ? 'border-gray-700 bg-gray-800' : 'border-gray-200 bg-white'}`}>
        <div className="flex items-center space-x-4">
          <div className="flex-1 relative">
            <svg className={`absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 ${
              darkMode ? 'text-gray-400' : 'text-gray-500'
            }`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <input
              type="text"
              placeholder="Search logs..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className={`w-full pl-10 pr-4 py-2 rounded-lg border ${
                darkMode 
                  ? 'bg-gray-700 border-gray-600 text-white placeholder-gray-400' 
                  : 'bg-white border-gray-300 text-gray-900 placeholder-gray-500'
              } focus:ring-2 focus:ring-blue-500 focus:border-transparent`}
            />
          </div>
          
          <select
            value={logLevel}
            onChange={(e) => setLogLevel(e.target.value)}
            className={`px-3 py-2 rounded-lg border ${
              darkMode 
                ? 'bg-gray-700 border-gray-600 text-white' 
                : 'bg-white border-gray-300 text-gray-900'
            } focus:ring-2 focus:ring-blue-500 focus:border-transparent`}
          >
            <option value="ALL">All Levels</option>
            <option value="ERROR">Error</option>
            <option value="WARN">Warning</option>
            <option value="INFO">Info</option>
            <option value="DEBUG">Debug</option>
          </select>
        </div>
      </div>

      {/* Logs List */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
        <div className="space-y-3">
          {logs.map((log, index) => (
            <div key={index} className={`rounded-lg border p-4 transition-all duration-200 hover:shadow-md ${
              darkMode ? 'border-gray-700 bg-gray-800' : 'border-gray-200 bg-white'
            }`}>
              <div className="flex items-start space-x-3">
                <div className={`px-2 py-1 rounded text-xs font-bold ${getLevelColor(log.level)}`}>
                  {log.level}
                </div>
                <div className="flex-1 min-w-0">
                  <p className={`text-sm font-medium ${darkMode ? 'text-gray-200' : 'text-gray-900'}`}>
                    {log.message}
                  </p>
                  <div className="flex items-center space-x-4 mt-2">
                    <span className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                      {format(log.timestamp, 'HH:mm:ss.SSS')}
                    </span>
                    <span className={`text-xs px-2 py-1 rounded ${
                      darkMode ? 'bg-gray-700 text-gray-300' : 'bg-gray-100 text-gray-600'
                    }`}>
                      {log.node}
                    </span>
                  </div>
                  {log.details && (
                    <div className={`mt-3 p-3 rounded ${darkMode ? 'bg-gray-700' : 'bg-gray-50'}`}>
                      <pre className={`text-xs font-mono ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                        {JSON.stringify(log.details, null, 2)}
                      </pre>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

