const HistoryView: React.FC<{
  history: any[];
  darkMode: boolean;
  checkpointIndex: number;
  setCheckpointIndex: (index: number) => void;
}> = ({ history, darkMode, checkpointIndex, setCheckpointIndex }) => {
  const { startGlobalExecution } = useStudioStore();

  const handleReplay = (checkpointId: string) => {
    startGlobalExecution('graph', { checkpoint_id: checkpointId });
  };

  const handlePrev = () => {
    if (checkpointIndex > 0) setCheckpointIndex(checkpointIndex - 1);
  };

  const handleNext = () => {
    if (checkpointIndex < history.length - 1) setCheckpointIndex(checkpointIndex + 1);
  };

  // Clamp index to valid range when history changes
  const safeIndex = history.length > 0 ? Math.min(checkpointIndex, history.length - 1) : 0;

  return (
    <div className="h-full overflow-y-auto p-6 custom-scrollbar">
      <div className="max-w-4xl mx-auto space-y-4">
        <div className="flex items-center justify-between">
          <div>
            <h3 className={`text-lg font-semibold ${darkMode ? 'text-white' : 'text-gray-900'}`}>
              Time Travel Debugging
            </h3>
            <p className={`text-sm mb-2 ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>
              Review past states and fork execution from any checkpoint.
            </p>
          </div>

          {/* Checkpoint Navigation */}
          {history.length > 1 && (
            <div className={`flex items-center space-x-2 px-3 py-2 rounded-lg border ${
              darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'
            }`}>
              <button
                onClick={handlePrev}
                disabled={safeIndex === 0}
                className={`p-1 rounded transition-colors ${
                  safeIndex === 0
                    ? darkMode ? 'text-gray-600 cursor-not-allowed' : 'text-gray-300 cursor-not-allowed'
                    : darkMode ? 'text-gray-300 hover:bg-gray-700' : 'text-gray-600 hover:bg-gray-100'
                }`}
                title="Previous checkpoint"
              >
                <ChevronLeftIcon className="w-5 h-5" />
              </button>
              <span className={`text-sm font-medium min-w-[4rem] text-center ${
                darkMode ? 'text-gray-300' : 'text-gray-700'
              }`}>
                {safeIndex + 1} / {history.length}
              </span>
              <button
                onClick={handleNext}
                disabled={safeIndex >= history.length - 1}
                className={`p-1 rounded transition-colors ${
                  safeIndex >= history.length - 1
                    ? darkMode ? 'text-gray-600 cursor-not-allowed' : 'text-gray-300 cursor-not-allowed'
                    : darkMode ? 'text-gray-300 hover:bg-gray-700' : 'text-gray-600 hover:bg-gray-100'
                }`}
                title="Next checkpoint"
              >
                <ChevronRightIcon className="w-5 h-5" />
              </button>
            </div>
          )}
        </div>
        
        {history.length === 0 ? (
          <div className={`p-8 text-center rounded-xl border ${darkMode ? 'bg-gray-800 border-gray-700 text-gray-400' : 'bg-gray-50 border-gray-200 text-gray-500'}`}>
            No history available for this thread.
          </div>
        ) : (
          <div className="space-y-4">
            {history.map((cp, index) => (
              <div key={cp.id} className={`p-4 rounded-xl border flex items-center justify-between ${
                index === safeIndex
                  ? darkMode
                    ? 'bg-blue-900/20 border-blue-700 ring-1 ring-blue-600'
                    : 'bg-blue-50 border-blue-300 ring-1 ring-blue-400'
                  : darkMode
                    ? 'bg-gray-800 border-gray-700 hover:bg-gray-750'
                    : 'bg-white border-gray-200 hover:bg-gray-50'
              } transition-colors cursor-pointer`}
                onClick={() => setCheckpointIndex(index)}
              >
                <div className="flex items-center space-x-4">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm ${
                    index === safeIndex
                      ? 'bg-blue-600 text-white'
                      : darkMode ? 'bg-blue-900 text-blue-300' : 'bg-blue-100 text-blue-700'
                  }`}>
                    {index + 1}
                  </div>
                  <div>
                    <div className={`font-medium ${darkMode ? 'text-gray-200' : 'text-gray-900'}`}>
                      Checkpoint {cp.id.slice(0, 8)}...
                    </div>
                    <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                      {new Date(cp.timestamp).toLocaleString()}
                    </div>
                  </div>
                </div>
                
                <div className="flex items-center space-x-4">
                  <div className={`text-sm ${darkMode ? 'text-gray-400' : 'text-gray-600'}`}>
                    {Object.keys(cp.state || {}).length} variables
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleReplay(cp.id); }}
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg shadow-sm transition-colors flex items-center"
                  >
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    Replay from here
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default DebugView; 