import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStudioStore, setStudioApiClient } from '../../store/useStudioStore';
import { AgentomaticConfig } from '../../types';
import toast from 'react-hot-toast';
import { AgentomaticClient } from '../../api/client';
import type { AgentInfo, ServerInfo } from '../../api/types';

interface HealthStatus {
  status: 'idle' | 'checking' | 'success' | 'error';
  message: string;
  lastChecked?: Date;
}

interface AvailableGraph {
  id: string;
  name: string;
  description?: string;
  config?: any;
}

// localStorage keys for persisting connection settings
const LS_KEY_URL = 'agentomatic-studio:lastUrl';
const LS_KEY_API_KEY = 'agentomatic-studio:lastApiKey';

// Color mapping for capability badges
const CAPABILITY_COLORS: Record<string, { light: string; dark: string }> = {
  graph:       { light: 'bg-blue-100 text-blue-700 border-blue-200',       dark: 'bg-blue-900/40 text-blue-300 border-blue-700' },
  streaming:   { light: 'bg-green-100 text-green-700 border-green-200',   dark: 'bg-green-900/40 text-green-300 border-green-700' },
  hitl:        { light: 'bg-amber-100 text-amber-700 border-amber-200',   dark: 'bg-amber-900/40 text-amber-300 border-amber-700' },
  checkpoints: { light: 'bg-purple-100 text-purple-700 border-purple-200', dark: 'bg-purple-900/40 text-purple-300 border-purple-700' },
};
const DEFAULT_CAP_COLOR = { light: 'bg-gray-100 text-gray-700 border-gray-200', dark: 'bg-gray-700 text-gray-300 border-gray-600' };

export const ConnectionSetup: React.FC = () => {
  const navigate = useNavigate();
  const { setConfig, setIsConnected, setIsLoading, addAssistant, clearAssistants, fetchGraphData, darkMode } = useStudioStore();
  const [formData, setFormData] = useState<AgentomaticConfig>(() => {
    // Hydrate defaults from localStorage when available
    const savedUrl = localStorage.getItem(LS_KEY_URL);
    const savedKey = localStorage.getItem(LS_KEY_API_KEY);
    return {
      apiUrl: savedUrl || 'http://127.0.0.1:8000',
      agentId: '',
      apiKey: savedKey || '',
    };
  });
  
  const [healthStatus, setHealthStatus] = useState<HealthStatus>({
    status: 'idle',
    message: 'Enter server URL to check connectivity'
  });
  
  const [availableGraphs, setAvailableGraphs] = useState<AvailableGraph[]>([]);
  const [isLoadingGraphs, setIsLoadingGraphs] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [showGraphs, setShowGraphs] = useState(false);
  const [serverInfo, setServerInfo] = useState<ServerInfo | null>(null);
  const [agentCapabilities, setAgentCapabilities] = useState<Record<string, string[]>>({});

  /** Persist connection settings to localStorage */
  const persistConnectionSettings = useCallback((url: string, apiKey: string) => {
    try {
      localStorage.setItem(LS_KEY_URL, url);
      if (apiKey) {
        localStorage.setItem(LS_KEY_API_KEY, apiKey);
      } else {
        localStorage.removeItem(LS_KEY_API_KEY);
      }
    } catch {
      // localStorage might be unavailable (private browsing, quota, etc.)
    }
  }, []);

  /** Render a capability badge pill */
  const renderCapabilityBadge = useCallback((cap: string) => {
    const colors = CAPABILITY_COLORS[cap] || DEFAULT_CAP_COLOR;
    const colorClass = darkMode ? colors.dark : colors.light;
    return (
      <span
        key={cap}
        className={`inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-semibold border leading-tight ${colorClass}`}
      >
        {cap}
      </span>
    );
  }, [darkMode]);

  // Debounced health check when URL changes
  const checkHealth = useCallback(async (url: string) => {
    if (!url || !url.startsWith('http')) {
      setHealthStatus({ status: 'idle', message: 'Enter a valid server URL' });
      setShowGraphs(false);
      return;
    }
    setHealthStatus({ status: 'checking', message: 'Checking server connectivity...' });
    try {
      // Try Studio API first
      const tempClient = new AgentomaticClient(url, formData.apiKey || undefined);
      const info = await tempClient.getServerInfo();
      setServerInfo(info);
      setHealthStatus({
        status: 'success',
        message: `Connected to ${info.platform_title || 'Agentomatic'} v${info.version} — ${info.agent_count} agent(s)`,
        lastChecked: new Date()
      });
      // Fetch agents via Studio API
      try {
        const agents = await tempClient.listAgents();
        const graphs: AvailableGraph[] = agents.map((agent: AgentInfo) => ({
          id: agent.slug || agent.name,
          name: agent.name,
          description: agent.description || `${agent.framework} agent`,
          config: { capabilities: agent.capabilities, has_graph: agent.has_graph, version: agent.version }
        }));
        const caps: Record<string, string[]> = {};
        agents.forEach(a => { caps[a.slug || a.name] = a.capabilities || []; });
        setAgentCapabilities(caps);
        setAvailableGraphs(graphs);
        if (graphs.length > 0 && !formData.agentId) {
          setFormData(prev => ({ ...prev, agentId: graphs[0].id }));
        }
      } catch (agentErr) {
        console.warn('Could not list agents:', agentErr);
      }
      setTimeout(() => setShowGraphs(true), 300);
    } catch (studioError) {
      // Fallback to legacy /health
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 5000);
        const response = await fetch(`${url}/health`, { method: 'GET', headers: { 'Content-Type': 'application/json' }, signal: controller.signal });
        clearTimeout(timeoutId);
        if (response.ok) {
          setHealthStatus({ status: 'success', message: 'Server is online (legacy mode)', lastChecked: new Date() });
          await fetchAvailableGraphs(url);
          setTimeout(() => setShowGraphs(true), 300);
        } else {
          setHealthStatus({ status: 'error', message: `Server responded with status: ${response.status}`, lastChecked: new Date() });
          setShowGraphs(false);
        }
      } catch (fallbackError: any) {
        let message = 'Connection failed';
        if (fallbackError.name === 'AbortError') {
          message = 'Server took too long to respond. Check if it\'s overloaded or behind a slow proxy.';
        } else if (
          fallbackError.message?.includes('Failed to fetch') ||
          fallbackError.message?.includes('NetworkError') ||
          fallbackError.message?.includes('ERR_CONNECTION_REFUSED')
        ) {
          message = 'Server is not running. Start it with: agentomatic run --studio';
        } else if (
          fallbackError.message?.includes('CORS') ||
          fallbackError.message?.includes('cross-origin') ||
          fallbackError.message?.includes('Access-Control')
        ) {
          message = 'CORS error detected. Ensure the server allows connections from this origin.';
        } else if (fallbackError.message) {
          message = `Connection error: ${fallbackError.message}`;
        }
        setHealthStatus({ status: 'error', message, lastChecked: new Date() });
        setShowGraphs(false);
      }
    }
  }, [formData.apiKey]);

  const fetchAvailableGraphs = useCallback(async (url: string) => {
    setIsLoadingGraphs(true);
    try {
      const response = await fetch(`${url}/agents`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          ...(formData.apiKey && {
            'X-Api-Key': formData.apiKey,
            Authorization: `Bearer ${formData.apiKey}`,
          }),
        },
      });

      if (response.ok) {
        const data = await response.json();
        console.log('Available graphs:', data);
        
        // Handle Agentomatic response format
        let graphs: AvailableGraph[] = [];
        if (data.agents && Array.isArray(data.agents)) {
          graphs = data.agents.map((item: any) => ({
            id: item.id || item.name,
            name: item.name || item.id,
            description: item.description || `Agentomatic Agent: ${item.name || item.id}`,
            config: item.config || {}
          }));
        } else if (Array.isArray(data)) {
          graphs = data.map((item: any) => ({
            id: item.id || item.name,
            name: item.name || item.id,
            description: item.description || `Agentomatic Agent: ${item.name || item.id}`,
            config: item.config || {}
          }));
        }

        setAvailableGraphs(graphs);
        
        // Auto-select first graph if none selected
        if (graphs.length > 0 && !formData.agentId) {
          setFormData(prev => ({ ...prev, agentId: graphs[0].id }));
        }
      } else {
        // Fallback to default graphs if endpoint doesn't exist
        const defaultGraphs = [
          { id: 'retrieval_graph', name: 'Retrieval Graph', description: 'RAG-based retrieval assistant' },
          { id: 'researcher_graph', name: 'Research Graph', description: 'Multi-step research assistant' },
          { id: 'chat_agent', name: 'Chat Agent', description: 'Conversational AI assistant' },
          { id: 'indexer', name: 'Indexer', description: 'Document indexing graph' }
        ];
        setAvailableGraphs(defaultGraphs);
      }
    } catch (error) {
      console.log('Could not fetch graphs, using defaults');
      const defaultGraphs = [
        { id: 'retrieval_graph', name: 'Retrieval Graph', description: 'RAG-based retrieval assistant' },
        { id: 'researcher_graph', name: 'Research Graph', description: 'Multi-step research assistant' },
        { id: 'chat_agent', name: 'Chat Agent', description: 'Conversational AI assistant' },
        { id: 'indexer', name: 'Indexer', description: 'Document indexing graph' }
      ];
      setAvailableGraphs(defaultGraphs);
    } finally {
      setIsLoadingGraphs(false);
    }
  }, [formData.agentId]);

  // Debounced URL change effect
  useEffect(() => {
    const timeoutId = setTimeout(() => {
      if (formData.apiUrl) {
        checkHealth(formData.apiUrl);
      }
    }, 1000); // 1 second debounce

    return () => clearTimeout(timeoutId);
  }, [formData.apiUrl, checkHealth]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (healthStatus.status !== 'success') {
      toast.error('Please ensure the server connection is healthy before connecting');
      return;
    }

    if (!formData.agentId) {
      toast.error('Please select a graph to use');
      return;
    }

    setIsConnecting(true);
    setIsLoading(true);

    try {
      // Try Studio API first
      let connectedViaStudio = false;
      try {
        const client = new AgentomaticClient(formData.apiUrl, formData.apiKey || undefined);
        const info = await client.getServerInfo();
        // Store the client globally so execution code can use it
        setStudioApiClient(client);
        clearAssistants();
        setConfig(formData);
        setIsConnected(true);

        const agents = await client.listAgents();
        agents.forEach((agent: AgentInfo) => {
          addAssistant({
            id: agent.slug || agent.name,
            name: agent.name,
            description: agent.description || '',
            type: 'chat' as const,
            model: agent.framework || 'unknown',
            provider: 'agentomatic',
            temperature: 0.7, maxTokens: 1000, maxIterations: 10,
            tools: [], enableStreaming: agent.capabilities?.includes('streaming') || false,
            timeout: 30000, config: { capabilities: agent.capabilities },
            graph_id: agent.slug || agent.name,
          });
        });

        if (agents.length > 0) {
          await fetchGraphData(agents[0].slug || agents[0].name);
        }

        persistConnectionSettings(formData.apiUrl, formData.apiKey || '');
        toast.success(`Connected to ${info.platform_title || 'Agentomatic'} v${info.version}!`);
        connectedViaStudio = true;
      } catch (studioErr) {
        console.warn('Studio API connection failed, trying legacy...', studioErr);
      }

      // Fallback to legacy connection
      if (!connectedViaStudio) {
        const response = await fetch(`${formData.apiUrl}/health`, {
          method: 'GET',
          headers: { 'Content-Type': 'application/json' }
        });
        if (response.ok) {
          clearAssistants();
          setConfig(formData);
          setIsConnected(true);
          try {
            const agentsResponse = await fetch(`${formData.apiUrl}/agents`, {
              method: 'GET',
              headers: {
                'Content-Type': 'application/json',
                ...(formData.apiKey && {
                  'X-Api-Key': formData.apiKey,
                  Authorization: `Bearer ${formData.apiKey}`,
                }),
              },
            });
            if (agentsResponse.ok) {
              const serverAgents = await agentsResponse.json();
              const agentsList = serverAgents.agents || [];
              if (Array.isArray(agentsList) && agentsList.length > 0) {
                agentsList.forEach((agent: any) => {
                  addAssistant({
                    id: agent.id, name: agent.name || agent.id, description: agent.description || '',
                    type: 'chat', model: 'gemma3:1b', provider: 'ollama',
                    temperature: 0.7, maxTokens: 1000, maxIterations: 10,
                    tools: [], enableStreaming: false, timeout: 30000,
                    config: agent.config || {}, graph_id: agent.id,
                  });
                });
                await fetchGraphData(agentsList[0].id);
              }
            }
          } catch (err) {
            console.warn('Could not fetch agents:', err);
          }
          persistConnectionSettings(formData.apiUrl, formData.apiKey || '');
          toast.success('Connected to Agentomatic server!');
        } else {
          throw new Error(`Server responded with status: ${response.status}`);
        }
      }

      setTimeout(() => navigate('/studio'), 500);
    } catch (error) {
      console.error('Connection error:', error);
      toast.error('Failed to connect. Please check your configuration.');
    } finally {
      setIsConnecting(false);
      setIsLoading(false);
    }
  };

  const handleInputChange = (field: keyof AgentomaticConfig, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleDemoMode = () => {
    console.log('Demo mode activated');
    
    // Clear any existing API client
    setStudioApiClient(null);
    
    // Set demo configuration
    const demoConfig = {
      apiUrl: 'http://localhost:3000', // Demo mode
      assistantId: 'demo_graph',
      apiKey: '',
    };
    
    setConfig(demoConfig);
    
    // Add demo assistants
    const demoAssistants = [
      {
        id: 'demo_graph',
        name: 'Demo Assistant',
        description: 'A sample assistant for demonstration',
        type: 'chat' as const,
        model: 'gpt-4',
        provider: 'openai',
        temperature: 0.7,
        maxTokens: 1000,
        maxIterations: 10,
        tools: [],
        enableStreaming: false,
        timeout: 30000,
        config: {},
        graph_id: 'demo_graph',
      },
      {
        id: 'retrieval_graph',
        name: 'Retrieval Assistant',
        description: 'RAG-based retrieval assistant',
        type: 'chat' as const,
        model: 'gpt-4',
        provider: 'openai',
        temperature: 0.7,
        maxTokens: 1000,
        maxIterations: 10,
        tools: [],
        enableStreaming: false,
        timeout: 30000,
        config: {},
        graph_id: 'retrieval_graph',
      },
      {
        id: 'researcher_graph',
        name: 'Research Assistant',
        description: 'Multi-step research assistant',
        type: 'chat' as const,
        model: 'gpt-4',
        provider: 'openai',
        temperature: 0.7,
        maxTokens: 1000,
        maxIterations: 10,
        tools: [],
        enableStreaming: false,
        timeout: 30000,
        config: {},
        graph_id: 'researcher_graph',
      }
    ];
    
    demoAssistants.forEach(assistant => addAssistant(assistant));
    
    // Set connected state
    setIsConnected(true);
    
    // Show success message
    toast.success('Demo mode activated! Explore the interface with sample data.');
    
    // Navigate to studio
    setTimeout(() => {
      navigate('/studio');
    }, 500);
  };

  const getStatusIcon = () => {
    switch (healthStatus.status) {
      case 'checking':
        return (
          <svg className="w-5 h-5 animate-spin text-blue-500" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
        );
      case 'success':
        return (
          <svg className="w-5 h-5 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        );
      case 'error':
        return (
          <svg className="w-5 h-5 text-red-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        );
      default:
        return (
          <svg className="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        );
    }
  };

  const getStatusColor = () => {
    switch (healthStatus.status) {
      case 'checking': return 'text-blue-600 bg-blue-50 border-blue-200';
      case 'success': return 'text-green-600 bg-green-50 border-green-200';
      case 'error': return 'text-red-600 bg-red-50 border-red-200';
      default: return 'text-gray-600 bg-gray-50 border-gray-200';
    }
  };

  const getDarkStatusColor = () => {
    switch (healthStatus.status) {
      case 'checking': return 'text-blue-400 bg-blue-900/30 border-blue-700';
      case 'success': return 'text-green-400 bg-green-900/30 border-green-700';
      case 'error': return 'text-red-400 bg-red-900/30 border-red-700';
      default: return 'text-gray-400 bg-gray-800 border-gray-600';
    }
  };

  return (
    <div className={`min-h-screen w-full flex ${
      darkMode 
        ? 'bg-gradient-to-br from-gray-900 via-gray-800 to-gray-900' 
        : 'bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50'
    } relative overflow-hidden`}>
      {/* Animated Background Elements */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute inset-0 bg-grid-pattern opacity-5"></div>
        <div className={`absolute top-1/4 left-1/4 w-96 h-96 rounded-full blur-3xl opacity-20 animate-pulse ${
          darkMode ? 'bg-blue-600' : 'bg-blue-400'
        }`}></div>
        <div className={`absolute bottom-1/4 right-1/4 w-96 h-96 rounded-full blur-3xl opacity-20 animate-pulse delay-1000 ${
          darkMode ? 'bg-purple-600' : 'bg-purple-400'
        }`}></div>
        <div className={`absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-96 h-96 rounded-full blur-3xl opacity-10 animate-pulse delay-500 ${
          darkMode ? 'bg-indigo-600' : 'bg-indigo-400'
        }`}></div>
      </div>

      {/* Main Content */}
      <div className="relative z-10 w-full flex">
        {/* Left Side - Hero Section */}
        <div className="hidden lg:flex lg:w-1/2 xl:w-2/5 flex-col justify-center items-center p-12 relative">
          <div className="max-w-md text-center animate-slide-in-left">
            <div className={`w-32 h-32 rounded-3xl flex items-center justify-center mx-auto mb-8 ${
              darkMode 
                ? 'bg-gradient-to-br from-blue-600 via-purple-600 to-indigo-600' 
                : 'bg-gradient-to-br from-blue-500 via-indigo-500 to-purple-600'
            } shadow-2xl animate-pulse-glow`}>
              <svg className="w-16 h-16 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            
            <h1 className={`text-5xl font-bold mb-6 ${darkMode ? 'text-white' : 'text-gray-900'}`}>
              Agentomatic
              <span className={`block text-4xl ${darkMode ? 'text-violet-400' : 'text-violet-600'}`}>
                Studio
              </span>
            </h1>
            
            <p className={`text-xl leading-relaxed mb-8 ${darkMode ? 'text-gray-300' : 'text-gray-600'}`}>
              Build, debug, and deploy intelligent agent workflows with visual graph execution
            </p>

            <div className="space-y-4">
              <div className={`flex items-center space-x-3 p-4 rounded-xl ${
                darkMode ? 'bg-gray-800/50' : 'bg-white/50'
              } backdrop-blur-sm`}>
                <div className={`w-3 h-3 rounded-full ${darkMode ? 'bg-green-400' : 'bg-green-500'} animate-pulse`}></div>
                <span className={`text-sm ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                  Real-time graph execution
                </span>
              </div>
              <div className={`flex items-center space-x-3 p-4 rounded-xl ${
                darkMode ? 'bg-gray-800/50' : 'bg-white/50'
              } backdrop-blur-sm`}>
                <div className={`w-3 h-3 rounded-full ${darkMode ? 'bg-blue-400' : 'bg-blue-500'} animate-pulse delay-300`}></div>
                <span className={`text-sm ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                  Interactive debugging tools
                </span>
              </div>
              <div className={`flex items-center space-x-3 p-4 rounded-xl ${
                darkMode ? 'bg-gray-800/50' : 'bg-white/50'
              } backdrop-blur-sm`}>
                <div className={`w-3 h-3 rounded-full ${darkMode ? 'bg-purple-400' : 'bg-purple-500'} animate-pulse delay-700`}></div>
                <span className={`text-sm ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                  Multi-agent orchestration
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* Right Side - Setup Form */}
        <div className="w-full lg:w-1/2 xl:w-3/5 flex items-center justify-center p-6 lg:p-12">
          <div className={`w-full max-w-md rounded-3xl shadow-2xl backdrop-blur-md border ${
            darkMode 
              ? 'bg-gray-800/80 border-gray-700' 
              : 'bg-white/80 border-gray-200'
          } animate-slide-in-right`}>
            
            {/* Header */}
            <div className="p-8 text-center">
              <div className="lg:hidden mb-6">
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mx-auto ${
                  darkMode 
                    ? 'bg-gradient-to-br from-blue-600 to-purple-600' 
                    : 'bg-gradient-to-br from-blue-500 to-indigo-600'
                } shadow-lg`}>
                  <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                </div>
              </div>
              
              <h2 className={`text-2xl lg:text-3xl font-bold mb-3 ${darkMode ? 'text-white' : 'text-gray-900'}`}>
                Get Started
              </h2>
              <p className={`text-lg ${darkMode ? 'text-gray-300' : 'text-gray-600'}`}>
                Connect to your server or try demo mode
              </p>
            </div>

            {/* Form */}
            <div className="px-8 pb-8">
              <form onSubmit={handleSubmit} className="space-y-6">
                {/* Server URL with Health Status */}
                <div className="animate-fade-in-up stagger-1">
                  <label className={`block text-sm font-semibold mb-3 ${darkMode ? 'text-gray-200' : 'text-gray-700'}`}>
                    Server URL
                  </label>
                  <div className="relative">
                    <input
                      type="url"
                      value={formData.apiUrl}
                      onChange={(e) => handleInputChange('apiUrl', e.target.value)}
                      placeholder="http://127.0.0.1:8000"
                      className={`w-full px-4 py-4 pr-14 border rounded-2xl shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-300 ${
                        darkMode 
                          ? 'bg-gray-700/50 border-gray-600 text-white placeholder-gray-400' 
                          : 'bg-white/50 border-gray-300 text-gray-900 placeholder-gray-500'
                      } backdrop-blur-sm`}
                      required
                    />
                    <div className="absolute right-4 top-1/2 transform -translate-y-1/2">
                      {getStatusIcon()}
                    </div>
                  </div>
                  
                  {/* Health Status Indicator */}
                  <div className={`mt-3 p-4 rounded-xl border text-sm flex items-center space-x-3 transition-all duration-300 ${
                    darkMode ? getDarkStatusColor() : getStatusColor()
                  }`}>
                    {getStatusIcon()}
                    <div className="flex-1">
                      <span className="font-medium">{healthStatus.message}</span>
                      {healthStatus.lastChecked && (
                        <div className="text-xs opacity-75 mt-1">
                          Last checked: {healthStatus.lastChecked.toLocaleTimeString()}
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                {/* Available Graphs */}
                {showGraphs && (
                  <div className="animate-fade-in-up stagger-2">
                    <label className={`block text-sm font-semibold mb-3 ${darkMode ? 'text-gray-200' : 'text-gray-700'}`}>
                      Available Graphs
                      {isLoadingGraphs && (
                        <span className="ml-2 text-xs text-blue-500">
                          <svg className="inline w-3 h-3 animate-spin mr-1" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                          </svg>
                          Loading...
                        </span>
                      )}
                    </label>
                    
                    {availableGraphs.length > 0 ? (
                      <div className="space-y-3 max-h-48 overflow-y-auto custom-scrollbar">
                        {availableGraphs.map((graph, index) => (
                          <label
                            key={graph.id}
                            className={`flex items-center p-4 rounded-xl border cursor-pointer transition-all duration-300 transform hover:scale-105 ${
                              formData.agentId === graph.id
                                ? darkMode
                                  ? 'bg-blue-900/40 border-blue-500 text-blue-400 shadow-lg'
                                  : 'bg-blue-50 border-blue-500 text-blue-700 shadow-lg'
                                : darkMode
                                  ? 'bg-gray-700/50 border-gray-600 hover:bg-gray-600/50 text-gray-200'
                                  : 'bg-white/50 border-gray-200 hover:bg-gray-50 text-gray-700'
                            } animate-slide-in-right`}
                            style={{ animationDelay: `${index * 100}ms` }}
                          >
                            <input
                              type="radio"
                              name="agentId"
                              value={graph.id}
                              checked={formData.agentId === graph.id}
                              onChange={(e) => handleInputChange('agentId', e.target.value)}
                              className="sr-only"
                            />
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2 flex-wrap">
                                <span className="font-semibold">{graph.name}</span>
                                {agentCapabilities[graph.id]?.length > 0 && (
                                  <span className="flex flex-wrap gap-1">
                                    {agentCapabilities[graph.id].map(renderCapabilityBadge)}
                                  </span>
                                )}
                              </div>
                              {graph.description && (
                                <div className={`text-sm mt-1 ${
                                  formData.agentId === graph.id
                                    ? 'opacity-90'
                                    : darkMode ? 'text-gray-400' : 'text-gray-500'
                                }`}>
                                  {graph.description}
                                </div>
                              )}
                            </div>
                            <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-200 ${
                              formData.agentId === graph.id
                                ? 'border-current scale-110'
                                : darkMode ? 'border-gray-500' : 'border-gray-300'
                            }`}>
                              {formData.agentId === graph.id && (
                                <div className="w-3 h-3 rounded-full bg-current animate-pulse"></div>
                              )}
                            </div>
                          </label>
                        ))}
                      </div>
                    ) : (
                      <div className={`p-6 rounded-xl border text-center ${
                        darkMode ? 'bg-gray-700/50 border-gray-600 text-gray-400' : 'bg-gray-50 border-gray-200 text-gray-500'
                      }`}>
                        {isLoadingGraphs ? (
                          <div className="flex items-center justify-center space-x-2">
                            <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
                              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                            <span>Loading graphs...</span>
                          </div>
                        ) : (
                          'No graphs available. Check server connection.'
                        )}
                      </div>
                    )}
                  </div>
                )}

                {/* Action Buttons */}
                <div className="space-y-4 animate-fade-in-up stagger-3">
                  <button
                    type="submit"
                    disabled={healthStatus.status !== 'success' || !formData.agentId || isConnecting}
                    className={`w-full py-4 px-6 rounded-2xl font-semibold text-white transition-all duration-300 transform ${
                      healthStatus.status === 'success' && formData.agentId && !isConnecting
                        ? 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 hover:scale-105 shadow-lg hover:shadow-2xl'
                        : 'bg-gray-400 cursor-not-allowed opacity-50'
                    }`}
                  >
                    {isConnecting ? (
                      <div className="flex items-center justify-center space-x-3">
                        <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
                          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        <span>Connecting...</span>
                      </div>
                    ) : (
                      'Connect to Server'
                    )}
                  </button>

                  <div className={`relative flex items-center justify-center ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                    <div className="absolute inset-0 flex items-center">
                      <div className={`w-full border-t ${darkMode ? 'border-gray-600' : 'border-gray-300'}`}></div>
                    </div>
                    <div className={`relative px-4 text-sm font-medium ${darkMode ? 'bg-gray-800' : 'bg-white'}`}>
                      or
                    </div>
                  </div>

                  <button
                    type="button"
                    onClick={handleDemoMode}
                    className={`w-full py-4 px-6 rounded-2xl font-semibold transition-all duration-300 transform hover:scale-105 ${
                      darkMode
                        ? 'bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-700 hover:to-emerald-700 text-white'
                        : 'bg-gradient-to-r from-green-500 to-emerald-500 hover:from-green-600 hover:to-emerald-600 text-white'
                    } shadow-lg hover:shadow-2xl`}
                  >
                    <div className="flex items-center justify-center space-x-3">
                      <span className="text-xl">🚀</span>
                      <span>Try Demo Mode</span>
                    </div>
                  </button>
                </div>
              </form>

              {/* Quick Info */}
              <div className={`mt-8 pt-6 border-t ${darkMode ? 'border-gray-600' : 'border-gray-200'} animate-fade-in-up stagger-4`}>
                <div className="grid grid-cols-2 gap-4 text-center">
                  <div className={`p-3 rounded-xl ${darkMode ? 'bg-gray-700/50' : 'bg-gray-50'}`}>
                    <div className={`text-2xl mb-1 ${darkMode ? 'text-green-400' : 'text-green-600'}`}>🚀</div>
                    <div className={`text-xs font-medium ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                      Demo Mode
                    </div>
                    <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                      No setup needed
                    </div>
                  </div>
                  <div className={`p-3 rounded-xl ${darkMode ? 'bg-gray-700/50' : 'bg-gray-50'}`}>
                    <div className={`text-2xl mb-1 ${darkMode ? 'text-blue-400' : 'text-blue-600'}`}>🔗</div>
                    <div className={`text-xs font-medium ${darkMode ? 'text-gray-300' : 'text-gray-700'}`}>
                      Server Mode
                    </div>
                    <div className={`text-xs ${darkMode ? 'text-gray-400' : 'text-gray-500'}`}>
                      Real execution
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}; 