import React, { useEffect, useState } from 'react';
import { useStudioStore } from '../../store/useStudioStore';
import { AgentomaticClient } from '../../api/client';
import { ControlEndpointInfo } from '../../api/types';

export const EndpointsView: React.FC = () => {
  const { config, darkMode } = useStudioStore();
  const [endpoints, setEndpoints] = useState<ControlEndpointInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchEndpoints = async () => {
      try {
        if (!config?.apiUrl) return;
        const client = new AgentomaticClient(config.apiUrl, config.apiKey || undefined);
        const data = await client.listControlEndpoints();
        setEndpoints(data);
        setError(null);
      } catch (err: any) {
        setError(
          err?.status === 404
            ? 'Control plane is not enabled (start with enable_control_plane=True).'
            : err?.message || 'Failed to fetch endpoints',
        );
      } finally {
        setLoading(false);
      }
    };
    fetchEndpoints();
  }, [config?.apiUrl, config?.apiKey]);

  const card = darkMode ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200';
  const subtle = darkMode ? 'text-gray-400' : 'text-gray-600';

  return (
    <div className={`p-6 h-full overflow-y-auto ${darkMode ? 'text-white bg-gray-900' : 'text-gray-900 bg-gray-50'}`}>
      <h1 className="text-2xl font-bold mb-1">Custom Endpoints</h1>
      <p className={`text-sm mb-6 ${subtle}`}>Multi-model APIs that fan out to authenticated upstreams.</p>

      {loading && <div className={subtle}>Loading endpoints…</div>}
      {error && (
        <div className={`p-4 rounded-lg border mb-4 ${darkMode ? 'bg-red-900/30 border-red-800 text-red-200' : 'bg-red-50 border-red-200 text-red-700'}`}>
          {error}
        </div>
      )}
      {!loading && !error && endpoints.length === 0 && (
        <div className={subtle}>No custom endpoints registered.</div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {endpoints.map((ep) => (
          <div key={ep.name} className={`p-6 rounded-xl border ${card} shadow-sm`}>
            <div className="flex justify-between items-start mb-3">
              <h2 className="text-lg font-semibold">{ep.name}</h2>
              <span className="inline-flex items-center gap-1.5 text-xs">
                <span className={`w-2 h-2 rounded-full ${ep.ready ? 'bg-green-500' : 'bg-gray-400'}`} />
                {ep.ready ? 'Ready' : 'Idle'}
              </span>
            </div>
            <p className={`text-sm mb-4 ${subtle}`}>{ep.description || 'No description provided'}</p>

            <div className="flex flex-wrap gap-2 mb-4">
              {ep.methods.map((m) => (
                <span key={m} className={`px-2 py-0.5 rounded text-xs font-mono ${darkMode ? 'bg-gray-700 text-gray-200' : 'bg-gray-100 text-gray-700'}`}>
                  {m}
                </span>
              ))}
              <span className={`px-2 py-0.5 rounded text-xs font-mono ${darkMode ? 'bg-violet-900 text-violet-200' : 'bg-violet-100 text-violet-800'}`}>
                /api/v1/endpoints/{ep.name}{ep.path}
              </span>
            </div>

            <dl className="text-sm space-y-1">
              <div className="flex justify-between">
                <dt className={subtle}>Aggregation</dt>
                <dd className="font-medium">{ep.aggregation || '—'}</dd>
              </div>
              <div className="flex justify-between">
                <dt className={subtle}>Upstreams</dt>
                <dd className="font-medium">{ep.upstreams.length}</dd>
              </div>
              <div className="flex justify-between">
                <dt className={subtle}>Version</dt>
                <dd className="font-medium">v{ep.version}</dd>
              </div>
            </dl>

            {ep.upstreams.length > 0 && (
              <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
                <div className={`text-xs mb-2 ${subtle}`}>Upstreams</div>
                <div className="flex flex-wrap gap-1.5">
                  {ep.upstreams.map((u) => (
                    <span key={u} className={`px-2 py-0.5 rounded text-xs ${darkMode ? 'bg-gray-700' : 'bg-gray-100'}`}>
                      {u}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};
