import type {
  ServerInfo,
  AgentInfo,
  GraphTopology,
  AgentSchemas,
  Thread,
  Message,
  RunRequest,
  RunInfo,
  StateSnapshot,
  Checkpoint,
  PendingApproval,
  PipelineInfo,
  PipelineValidationResponse,
  PipelineRunResponse,
  PluginInfo,
  PluginModelCard,
  ControlInfo,
  ControlAgentInfo,
  ControlEndpointInfo,
  ControlConnectionInfo,
  ControlMetricsSummary,
  ToggleResponse,
} from './types';

/**
 * Centralized API client for the Agentomatic Studio backend.
 * Wraps all REST endpoints with typed request/response handling.
 */
export class AgentomaticClient {
  private baseUrl: string;
  private apiKey: string | null;
  private headers: Record<string, string>;

  constructor(baseUrl: string, apiKey?: string) {
    this.baseUrl = baseUrl.replace(/\/$/, ''); // Remove trailing slash
    this.apiKey = apiKey || null;
    // Send both headers so Studio works with API-key auth *and* JWT middleware
    // (JWT expects Authorization: Bearer; AuthMiddleware expects X-Api-Key).
    this.headers = {
      'Content-Type': 'application/json',
      ...(this.apiKey
        ? {
            'X-Api-Key': this.apiKey,
            Authorization: `Bearer ${this.apiKey}`,
          }
        : {}),
    };
  }

  /**
   * Generic request helper with error handling.
   * All API calls funnel through here for consistent header injection and error mapping.
   */
  private async request<T>(path: string, options?: RequestInit): Promise<T> {
    const url = `${this.baseUrl}${path}`;
    const response = await fetch(url, {
      ...options,
      headers: { ...this.headers, ...options?.headers },
    });
    if (!response.ok) {
      const errorBody = await response.text().catch(() => '');
      throw new ApiError(response.status, response.statusText, errorBody);
    }
    return response.json();
  }

  // --- Discovery ---

  async getServerInfo(): Promise<ServerInfo> {
    return this.request('/studio/info');
  }

  async listAgents(): Promise<AgentInfo[]> {
    return this.request('/studio/agents');
  }

  // --- Graph ---

  async getGraph(agent: string): Promise<GraphTopology> {
    return this.request(`/studio/agents/${agent}/graph`);
  }

  async getSchemas(agent: string): Promise<AgentSchemas> {
    return this.request(`/studio/agents/${agent}/schemas`);
  }

  async getAgentConfig(agent: string): Promise<Record<string, any>> {
    return this.request(`/studio/agents/${agent}/config`);
  }

  // --- Threads ---

  async createThread(agent: string, userId?: string, title?: string): Promise<Thread> {
    return this.request(`/api/v1/${agent}/threads`, {
      method: 'POST',
      body: JSON.stringify({ user_id: userId || 'default-user', title }),
    });
  }

  async listThreads(agent: string): Promise<Thread[]> {
    return this.request(`/api/v1/${agent}/threads`);
  }

  async getThread(agent: string, threadId: string): Promise<Thread> {
    return this.request(`/api/v1/${agent}/threads/${threadId}`);
  }

  async deleteThread(agent: string, threadId: string): Promise<void> {
    await this.request(`/api/v1/${agent}/threads/${threadId}`, { method: 'DELETE' });
  }

  async getMessages(agent: string, threadId: string): Promise<Message[]> {
    return this.request(`/api/v1/${agent}/threads/${threadId}/messages`);
  }

  async forkThread(agent: string, threadId: string, messageIndex: number): Promise<Thread> {
    return this.request(`/api/v1/${agent}/threads/${threadId}/fork`, {
      method: 'POST',
      body: JSON.stringify({ message_index: messageIndex }),
    });
  }

  // --- Runs ---

  async createRun(agent: string, request: RunRequest): Promise<RunInfo> {
    return this.request(`/studio/agents/${agent}/runs`, {
      method: 'POST',
      body: JSON.stringify(request),
    });
  }

  async listRuns(agent: string, limit: number = 50): Promise<RunInfo[]> {
    return this.request(`/studio/agents/${agent}/runs?limit=${limit}`);
  }

  async getRun(agent: string, runId: string): Promise<RunInfo> {
    return this.request(`/studio/agents/${agent}/runs/${runId}`);
  }

  // --- State ---

  async getState(agent: string, threadId: string): Promise<StateSnapshot> {
    return this.request(`/studio/agents/${agent}/threads/${threadId}/state`);
  }

  async updateState(agent: string, threadId: string, updates: Record<string, any>): Promise<StateSnapshot> {
    return this.request(`/studio/agents/${agent}/threads/${threadId}/state`, {
      method: 'POST',
      body: JSON.stringify({ updates }),
    });
  }

  async getHistory(agent: string, threadId: string): Promise<Checkpoint[]> {
    return this.request(`/studio/agents/${agent}/threads/${threadId}/history`);
  }

  // --- HITL ---

  async getPendingApprovals(agent: string, threadId: string): Promise<PendingApproval[]> {
    return this.request(`/api/v1/${agent}/threads/${threadId}/pending`);
  }

  async approve(agent: string, threadId: string, approvalId: string): Promise<void> {
    await this.request(`/api/v1/${agent}/threads/${threadId}/approve`, {
      method: 'POST',
      body: JSON.stringify({ approval_id: approvalId }),
    });
  }

  async reject(agent: string, threadId: string, approvalId: string, reason?: string): Promise<void> {
    await this.request(`/api/v1/${agent}/threads/${threadId}/reject`, {
      method: 'POST',
      body: JSON.stringify({ approval_id: approvalId, reason }),
    });
  }

  // --- Health ---

  async healthCheck(): Promise<boolean> {
    try {
      await this.request('/studio/info');
      return true;
    } catch {
      return false;
    }
  }

  // --- Pipelines ---

  async listPipelines(): Promise<PipelineInfo[]> {
    return this.request('/api/v1/pipelines');
  }

  async runPipeline(name: string, request: { input: any; metadata?: any }): Promise<PipelineRunResponse> {
    return this.request(`/api/v1/pipelines/${name}/run`, {
      method: 'POST',
      body: JSON.stringify(request),
    });
  }

  async validatePipeline(name: string): Promise<PipelineValidationResponse> {
    return this.request(`/api/v1/pipelines/${name}/validate`);
  }

  async getPipelineConfig(name: string): Promise<Record<string, any>> {
    return this.request(`/api/v1/pipelines/${name}/config`);
  }

  async visualizePipeline(name: string): Promise<{ mermaid: string }> {
    return this.request(`/api/v1/pipelines/${name}/visualize`);
  }

  // --- Plugins ---

  async listPlugins(): Promise<PluginInfo[]> {
    return this.request('/api/v1/plugins');
  }

  async getPluginModelCard(name: string): Promise<PluginModelCard> {
    return this.request(`/api/v1/plugins/${name}/model_card`);
  }

  async runPluginPredict(name: string, request: any): Promise<any> {
    return this.request(`/api/v1/plugins/${name}/predict`, {
      method: 'POST',
      body: JSON.stringify(request),
    });
  }

  // --- Control Plane ---
  // Mounted at {api_prefix}/control when enable_control_plane=True.
  // Mutating calls accept an optional X-Control-Token header.

  async getControlInfo(): Promise<ControlInfo> {
    return this.request('/api/v1/control');
  }

  async listControlAgents(): Promise<ControlAgentInfo[]> {
    return this.request('/api/v1/control/agents');
  }

  async getControlAgent(name: string): Promise<ControlAgentInfo> {
    return this.request(`/api/v1/control/agents/${name}`);
  }

  async listControlEndpoints(): Promise<ControlEndpointInfo[]> {
    return this.request('/api/v1/control/endpoints');
  }

  async listControlConnections(): Promise<ControlConnectionInfo[]> {
    return this.request('/api/v1/control/connections');
  }

  async getControlMetricsSummary(): Promise<ControlMetricsSummary> {
    return this.request('/api/v1/control/metrics/summary');
  }

  async getControlHealth(): Promise<Record<string, any>> {
    return this.request('/api/v1/control/health');
  }

  async getControlConfig(): Promise<Record<string, any>> {
    return this.request('/api/v1/control/config');
  }

  async setAgentEnabled(
    name: string,
    enabled: boolean,
    controlToken?: string,
  ): Promise<ToggleResponse> {
    const action = enabled ? 'enable' : 'disable';
    return this.request(`/api/v1/control/agents/${name}/${action}`, {
      method: 'POST',
      headers: controlToken ? { 'X-Control-Token': controlToken } : {},
    });
  }

  async setMaintenance(enabled: boolean, controlToken?: string): Promise<ToggleResponse> {
    return this.request('/api/v1/control/maintenance', {
      method: 'POST',
      headers: controlToken ? { 'X-Control-Token': controlToken } : {},
      body: JSON.stringify({ enabled }),
    });
  }

  // --- Streaming ---

  /** Returns the SSE stream URL for a given agent's run execution. */
  getStreamUrl(agent: string): string {
    return `${this.baseUrl}/studio/agents/${agent}/runs/stream`;
  }

  /** Returns a copy of the current request headers (useful for SSE connections). */
  getHeaders(): Record<string, string> {
    return { ...this.headers };
  }
}

/**
 * Structured API error with status code, status text, and response body.
 */
export class ApiError extends Error {
  constructor(
    public status: number,
    public statusText: string,
    public body: string,
  ) {
    super(`API Error ${status}: ${statusText}`);
    this.name = 'ApiError';
  }
}
